#!/usr/bin/env dart
// ignore_for_file: avoid_print

import 'dart:io';

import 'package:path/path.dart' as p;
import 'package:saropa_lints/src/scan/scan_diagnostic.dart';
import 'package:saropa_lints/src/scan/scan_runner.dart';

/// Standalone lint scanner that runs saropa_lints rules against any Dart
/// project without requiring it as a dependency.
///
/// Reads the project's analysis_options.yaml (generated by `init`) to
/// determine which rules are enabled. If no config exists, prompts the
/// user to run `init` first.
///
/// Usage:
///   dart run saropa_lints scan [path]
///   dart run saropa_lints:scan [path]
///
/// Exit codes:
///   0 - No issues found
///   1 - Issues found
///   2 - No configuration found
void main(List<String> args) {
  if (args.contains('--help') || args.contains('-h')) {
    _printUsage();
    return;
  }

  final path = _parsePath(args);

  final runner = ScanRunner(targetPath: path);
  final diagnostics = runner.run();

  if (diagnostics == null) {
    // No config found — runner already printed the error message
    exit(2);
  }

  if (diagnostics.isEmpty) {
    print('\nNo issues found.');
    exit(0);
  }

  final reportPath = _writeReport(diagnostics, path);
  _printSummary(diagnostics);
  print('Report: $reportPath');
  exit(1);
}

/// Write detailed results to a report file. Returns the file path.
String _writeReport(List<ScanDiagnostic> diagnostics, String targetPath) {
  final now = DateTime.now();
  final ts =
      '${now.year}${now.month.toString().padLeft(2, '0')}${now.day.toString().padLeft(2, '0')}_'
      '${now.hour.toString().padLeft(2, '0')}${now.minute.toString().padLeft(2, '0')}${now.second.toString().padLeft(2, '0')}';
  final dateFolder = ts.substring(0, 8);

  final reportsDir = Directory('reports/$dateFolder');
  if (!reportsDir.existsSync()) {
    reportsDir.createSync(recursive: true);
  }
  final reportFile = File('${reportsDir.path}/${ts}_scan_report.log');

  final buf = StringBuffer();
  buf.writeln('${'=' * 80}');
  buf.writeln('SAROPA LINTS SCAN REPORT');
  buf.writeln('Generated: ${now.toIso8601String()}');
  buf.writeln('Target: ${p.absolute(targetPath)}');
  buf.writeln('Total issues: ${diagnostics.length}');
  buf.writeln('${'=' * 80}');
  buf.writeln();

  // Group by file
  final byFile = <String, List<ScanDiagnostic>>{};
  for (final d in diagnostics) {
    byFile.putIfAbsent(d.filePath, () => []).add(d);
  }

  for (final entry in byFile.entries) {
    buf.writeln(entry.key);
    for (final d in entry.value) {
      buf.writeln('  ${d.severity.padRight(7)} '
          'line ${d.line.toString().padLeft(4)}  '
          '${d.ruleName}  ${d.problemMessage}');
    }
    buf.writeln();
  }

  // Summary by rule
  buf.writeln('${'─' * 80}');
  buf.writeln('ISSUES BY RULE');
  buf.writeln('${'─' * 80}');
  final byRule = <String, int>{};
  for (final d in diagnostics) {
    byRule[d.ruleName] = (byRule[d.ruleName] ?? 0) + 1;
  }
  final sortedRules = byRule.entries.toList()
    ..sort((a, b) => b.value.compareTo(a.value));
  for (final entry in sortedRules) {
    buf.writeln('  ${entry.value.toString().padLeft(6)}  ${entry.key}');
  }

  reportFile.writeAsStringSync(buf.toString());
  return reportFile.path;
}

/// Print a compact summary to terminal.
void _printSummary(List<ScanDiagnostic> diagnostics) {
  // Count by severity
  final bySeverity = <String, int>{};
  for (final d in diagnostics) {
    bySeverity[d.severity] = (bySeverity[d.severity] ?? 0) + 1;
  }

  // Count by rule (for top offenders)
  final byRule = <String, int>{};
  for (final d in diagnostics) {
    byRule[d.ruleName] = (byRule[d.ruleName] ?? 0) + 1;
  }

  // Count files affected
  final fileCount = diagnostics.map((d) => d.filePath).toSet().length;

  print('');
  print('${diagnostics.length} issue(s) in $fileCount file(s)');

  final parts = <String>[];
  for (final sev in ['ERROR', 'WARNING', 'INFO']) {
    final count = bySeverity[sev];
    if (count != null && count > 0) {
      parts.add('$count ${sev.toLowerCase()}');
    }
  }
  if (parts.isNotEmpty) {
    print('  ${parts.join(' · ')}');
  }

  // Top 10 rules
  final sortedRules = byRule.entries.toList()
    ..sort((a, b) => b.value.compareTo(a.value));
  final top = sortedRules.take(10);
  print('');
  print('Top rules:');
  for (final entry in top) {
    print('  ${entry.value.toString().padLeft(6)}  ${entry.key}');
  }
  if (sortedRules.length > 10) {
    print('  ... and ${sortedRules.length - 10} more (see report)');
  }
  print('');
}

String _parsePath(List<String> args) {
  for (final arg in args) {
    if (!arg.startsWith('--') && arg != 'scan') return arg;
  }
  return '.';
}

void _printUsage() {
  print('saropa_lints scan - Standalone lint scanner');
  print('');
  print('Runs the rules configured by "init" against any Dart project,');
  print('without requiring saropa_lints as a dependency in that project.');
  print('');
  print('Usage: dart run saropa_lints scan [path]');
  print('');
  print('Options:');
  print('  -h, --help     Show this help');
  print('');
  print('The target must have an analysis_options.yaml with saropa_lints');
  print('rules configured. If not, run init first:');
  print('');
  print('  dart run saropa_lints init --target /path/to/project');
  print('');
  print('Results are written to reports/<date>/<timestamp>_scan_report.log');
  print('');
  print('Examples:');
  print('  dart run saropa_lints init --target .       # 1. Configure rules');
  print('  dart run saropa_lints scan .                # 2. Run scan');
  print('  dart run saropa_lints scan /path/to/project');
}
